// 部署別システムプロンプトを決定
const dept = $input.item.json.runData.department;
const deptPrompts = {
  SALES: `あなたは優秀な営業アシスタントです。
以下を得意とします：
- 顧客向け提案書・メール文章の作成
- 見積書・提案資料の構成
- 商談フォロー文面の作成
- 営業戦略のアドバイス
回答は具体的かつ実用的に、すぐに使える形式で提供してください。`,
  MARKETING: `あなたは優秀なマーケティングアシスタントです。
以下を得意とします：
- SNS投稿・広告コピーの作成
- キャンペーン企画・施策提案
- ブランディング・メッセージング
- マーケティング戦略のアドバイス
回答はクリエイティブで、ターゲットに刺さる表現で提供してください。`,
  ACCOUNTING: `あなたは優秀な経理・財務アシスタントです。
以下を得意とします：
- 経費精算・請求書の処理方法
- 予算管理・財務分析のアドバイス
- 税務・会計に関する一般的な質問への回答
- 財務レポートの作成サポート
正確で信頼性の高い情報を提供してください。`,
  GENERAL: `あなたは優秀なビジネスアシスタントです。
幅広いビジネス課題に対して、実用的なアドバイスと具体的なサポートを提供します。
ユーザーの質問に対して丁寧かつ的確に回答してください。`
};

const systemPrompt = deptPrompts[dept] ?? deptPrompts.GENERAL;

// 会話履歴を OpenAI 形式に変換（Claude 互換）
const history = ($input.item.json.runData.history ?? []).slice(-8);
const messages = [
  { role: 'system', content: systemPrompt },
  ...history,
  { role: 'user', content: $input.item.json.runData.message }
];

return [{ json: {
  messages,
  department: dept ?? 'GENERAL',
  org_id: $input.item.json.runData.orgId,
  plan: $input.item.json.runData.plan ?? 'STARTER',
  aiEngineUrl: $input.item.json.runData.aiEngineUrl ?? 'http://ai-engine:8000'
} }];

// AI Engine /llm/chat の応答 = LLMResponse { content, model, tokens_used, latency_ms, ... }
const aiContent = $input.item.json.content ?? '';
const dept = $('Build Prompt').item.json.department;
return [{ json: { content: aiContent, department: dept } }];
